template <class Info>
class OfflineCatTree {
public:

	OfflineCatTree() : n(0) {}
	OfflineCatTree(int _n) { init(_n); }
	OfflineCatTree(vector<Info>& _init) { init(_init); }

	// 添加询问
	void add_query(int l, int r, int id, int t) {
		qs.push_back({ l, r, id, t });
	}

	// 核心处理函数，返回所有询问的结果
	vector<int>& solve() {
		if (qs.empty()) return ans;

		// 找到最大的 id 以调整答案数组大小
		int max_id = 0;
		for (const auto& q : qs)max_id = max(max_id, q.id);
		ans.assign(max_id + 1, 0);

		solve(1, n, qs);
		return ans;
	}

private:
	void init(int _n) {
		n = _n;
		info.assign(n + 1, Info());
		tmp.resize(n + 1);
		qs.clear();
	}

	void init(vector<Info>& _init) {
		n = _init.size() - 1;
		info = move(_init);
		tmp.resize(n + 1);
		qs.clear();
	}

	struct Query {
		// (可以修改，在这里可以加入更多参数)
		int l, r, id;
		int t;
	};

	int n;
	vector<Info> info;  // 存储原始数据 (下标 1 ~ n)
	vector<Query> qs;   // 存储询问
	vector<Info> tmp;   // O(N) 的全局缓存，用于计算前缀/后缀
	vector<int> ans;   // 存储最终算出的 Info (可以修改，不用 Info 输出)


	// 离线分治：利用递归特性，算完一层扔一层，空间 O(N)
	// 只要题目允许离线，离线猫树全面优于在线猫树，它保留了 O(1) 的合并次数，同时把空间降到了最低。
	// 若强制在线，使用线段树
	void solve(int l, int r, vector<Query>& q_curr) {
		if (q_curr.empty()) return;

		// 叶子节点：直接由 info[l] 贡献
		if (l == r) {
			for (const auto& q : q_curr) {
				ans[q.id] = info[l].dp[q.t];
			}
			return;
		}

		int mid = (l + r) >> 1;

		// --- 1. 预处理中间向两边的前缀/后缀 ---
		// 注意：这里复用了 tmp 数组，省内存

		// [mid, l] 后缀：从 mid 向左
		// tmp[i] = info[i] + tmp[i + 1]
		// Info 合并方向：(左边) + (右边)
		tmp[mid] = info[mid];
		for (int i = mid - 1; i >= l; i--) {
			tmp[i] = info[i] + tmp[i + 1];
		}

		// [mid + 1, r] 前缀：从 mid + 1 向右
		// tmp[i] = tmp[i - 1] + info[i]
		if (mid + 1 <= r) {
			tmp[mid + 1] = info[mid + 1];
			for (int i = mid + 2; i <= r; i++) {
				tmp[i] = tmp[i - 1] + info[i];
			}
		}

		// --- 2. 处理询问 ---
		vector<Query> q_left, q_right;
		// 预留空间稍微优化一点常数，不写也没事
		q_left.reserve(q_curr.size() / 2);
		q_right.reserve(q_curr.size() / 2);

		for (const auto& q : q_curr) {
			if (q.r <= mid) {
				q_left.push_back(q);
			}
			else if (q.l > mid) {
				q_right.push_back(q);
			}
			else {
				// 跨越 mid 的询问
				// Ans = Suffix[l] + Prefix[r]
				// (可以修改，对合并答案进行优化，而不是直接合并)

				const var& ldp = tmp[q.l].dp;
				const var& rdp = tmp[q.r].dp;
				fa(k, 0, q.t) {
					// 枚举 ldp 拿多少热量 k
					// rdp 拿 q.t - k 热量
					ans[q.id] = max(ans[q.id], ldp[k] + rdp[q.t - k]);
				}
			}
		}

		// 释放当前层内存
		q_curr.clear();

		// --- 3. 递归 ---
		solve(l, mid, q_left);
		solve(mid + 1, r, q_right);
	}
};
struct Info {
	Info() :h(0), w(0), is_item(0) { fill(all(dp), 0); }
	Info(int h, int w) :h(h), w(w), is_item(1) {
		fill(all(dp), 0);
		fb(i, 200, h) {
			dp[i] = max(dp[i], dp[i - h] + w);
		}
	}

	array<int, 201> dp;
	int h, w;
	bool is_item;

	int query_ans(int t) const {
		// 实现答案查询函数
		return dp[t];
	}
};

Info operator+(const Info& a, const Info& b) {
	Info res;
	res.is_item = 0;

	if (a.is_item and !b.is_item) {
		res = b;
		fb(i, 200, a.h) {
			res.dp[i] = max(res.dp[i], res.dp[i - a.h] + a.w);
		}
	}
	else if (!a.is_item and b.is_item) {
		res = a;
		fb(i, 200, b.h) {
			res.dp[i] = max(res.dp[i], res.dp[i - b.h] + b.w);
		}
	}
	else if (a.is_item and b.is_item) {
		fb(i, 200, a.h) {
			res.dp[i] = max(res.dp[i], res.dp[i - a.h] + a.w);
		}
		fb(i, 200, b.h) {
			res.dp[i] = max(res.dp[i], res.dp[i - b.h] + b.w);
		}
	}

	return res;
}
